const allErrors = new Map()

// Process each target
for await (const chunk of lines) {
  if (!chunk.startsWith('ERROR')) continue

  const [filename, code] = chunk.split(':')
  const lines = fileMap.get(filename) || []
  allErrors.set(filename.trim(), lines.concat([parseInt(code)]))
}

for (const file of Object.keys(allErrors)) {
  for (const line of allErrors.get(file)) {
    console.error(`${file}:${line}: type checking failed`)
  }
}

input.newString:
const allErrors = new Set()

// Process each target
for await (const chunk of lines) {
  if (!chunk.startsWith('ERROR')) continue

  const [filename, code] = chunk.split(':')
  const lines = fileMap.get(filename) || []
  allErrors.add(`${filename.trim()}:${code}`)
}

for (const error of allErrors) {
  const [file, line] = error.split(':')
  console.error(`${file}: type checking failed`)
}

